import dayjs, { Dayjs } from "dayjs";
import isSameOrAfter from "dayjs/plugin/isSameOrAfter";
import isSameOrBefore from "dayjs/plugin/isSameOrBefore";
import isoWeek from "dayjs/plugin/isoWeek";
import { parseAsString, parseAsStringLiteral, useQueryStates } from "nuqs";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { AggregationPeriod } from "@dfp/bw-isomorphic-enums";

import {
  DateRange,
  calculateDateRange,
  formatDateToISO,
  isDayWithinVisibleRange,
  useSelectedPeriodStore,
} from "../utils/index.ts";

dayjs.extend(isSameOrAfter);
dayjs.extend(isSameOrBefore);

// needed to use `isoWeek` in dayjs calculations, to set Monday as beginning of the week
dayjs.extend(isoWeek);

const INTERVAL_VALUES: AggregationPeriod[] = ["1W", "1M"] as const;

export type UseCashflowTimePeriodFilterOptions = {
  /** Number of columns available to display periods */
  columnCount: number;
  /**
   * Minimum date from BE settings (oldest transaction across selected accounts).
   * Falls back to 2 years ago during initial loading.
   */
  maxDateRangeFrom: string | undefined;
  /**
   * Maximum date from BE settings (furthest future period boundary).
   * Falls back to current date + 5 months during initial loading.
   */
  maxDateRangeTo: string | undefined;
  companyId: string;
};

export type UseCashflowTimePeriodFilterResult = {
  dateFrom: string;
  dateTo: string;
  /** Current interval granularity (1W or 1M) */
  interval: AggregationPeriod;
  setInterval: (interval: AggregationPeriod) => void;
  /** Currently selected day that determines the highlighted period */
  selectedDay: Dayjs;
  setPeriod: (day: Dayjs, newInterval?: AggregationPeriod) => void;
  goToPreviousPeriod: () => void;
  goToNextPeriod: () => void;
  canGoToPreviousPeriod: boolean;
  canGoToNextPeriod: boolean;
  /** Minimum selectable date (oldest available data) */
  maxDateRangeFrom: Dayjs;
  /** Maximum selectable date (from BE settings) */
  maxDateRangeTo: Dayjs;
};

/**
 * Hook for managing cashflow time period filtering and navigation.
 *
 * Handles:
 * - Interval selection (weekly/monthly)
 * - Date range calculation based on column count
 * - Period navigation (previous/next)
 * - Day selection with bounds clamping
 */
export function useCashflowTimePeriodFilter({
  columnCount,
  maxDateRangeFrom: maxDateRangeFromSetting,
  maxDateRangeTo: maxDateRangeToSetting,
  companyId,
}: UseCashflowTimePeriodFilterOptions): UseCashflowTimePeriodFilterResult {
  const { selectedDay, interval, updatePeriod } = usePeriodState(companyId);
  const selectedDayRef = useRef(selectedDay);
  const intervalRef = useRef(interval);

  selectedDayRef.current = selectedDay;
  intervalRef.current = interval;

  const maxDateRangeTo = useMemo(() => {
    if (maxDateRangeToSetting) {
      return dayjs(maxDateRangeToSetting);
    }
    return dayjs().add(5, "months").endOf("month");
  }, [maxDateRangeToSetting]);

  const maxDateRangeFrom = useMemo(() => {
    if (maxDateRangeFromSetting) {
      return dayjs(maxDateRangeFromSetting);
    }
    return dayjs().subtract(24, "months").startOf("month");
  }, [maxDateRangeFromSetting]);

  const [dateRange, setDateRange] = useState<DateRange>(() =>
    calculateDateRange(
      selectedDay,
      interval,
      columnCount,
      maxDateRangeFrom,
      maxDateRangeTo,
    ),
  );

  const setCalculatedDateRange = useCallback(
    (anchorDay: Dayjs, nextInterval: AggregationPeriod) => {
      const nextRange = calculateDateRange(
        anchorDay,
        nextInterval,
        columnCount,
        maxDateRangeFrom,
        maxDateRangeTo,
      );

      setDateRange((prev) =>
        prev.dateFrom === nextRange.dateFrom && prev.dateTo === nextRange.dateTo
          ? prev
          : nextRange,
      );
    },
    [columnCount, maxDateRangeFrom, maxDateRangeTo],
  );

  // Recalculate dateRange when non-user-initiated deps change
  // (interval toggle, column count resize, BE settings loading)
  useEffect(() => {
    setCalculatedDateRange(selectedDay, interval);
    // selectedDay is intentionally excluded — selectDay handles it conditionally
  }, [interval, setCalculatedDateRange]);

  /**
   * Navigate to previous period.
   * Shifts the view window by one period without changing selectedDay.
   */
  const goToPreviousPeriod = useCallback(() => {
    setDateRange((prev) => {
      const periodUnitPlural = interval === "1M" ? "months" : "weeks";
      const newFrom = dayjs(prev.dateFrom).subtract(1, periodUnitPlural);

      // Clamp: don't go before maxDateRangeFrom
      if (newFrom.isBefore(maxDateRangeFrom)) {
        return prev;
      }

      return calculateDateRange(
        newFrom,
        interval,
        columnCount,
        maxDateRangeFrom,
        maxDateRangeTo,
      );
    });
  }, [interval, columnCount, maxDateRangeFrom, maxDateRangeTo]);

  /**
   * Navigate to next period.
   * Shifts the view window by one period without changing selectedDay.
   */
  const goToNextPeriod = useCallback(() => {
    setDateRange((prev) => {
      const periodUnitPlural = interval === "1M" ? "months" : "weeks";
      const newFrom = dayjs(prev.dateFrom).add(1, periodUnitPlural);

      // Clamp: don't go past maxDateRangeTo
      if (newFrom.isAfter(maxDateRangeTo)) {
        return prev;
      }

      return calculateDateRange(
        newFrom,
        interval,
        columnCount,
        maxDateRangeFrom,
        maxDateRangeTo,
      );
    });
  }, [interval, columnCount, maxDateRangeFrom, maxDateRangeTo]);

  const setPeriod = useCallback(
    (day: Dayjs, newInterval?: AggregationPeriod) => {
      // Clamp to available range
      let clampedDay = day;
      if (day.isBefore(maxDateRangeFrom)) {
        clampedDay = maxDateRangeFrom;
      } else if (day.isAfter(maxDateRangeTo)) {
        clampedDay = maxDateRangeTo;
      }

      const effectiveInterval = newInterval ?? intervalRef.current;

      selectedDayRef.current = clampedDay;
      intervalRef.current = effectiveInterval;
      updatePeriod(clampedDay, newInterval);

      // Only shift the view if the selected day is outside the current visible range
      if (
        !isDayWithinVisibleRange(
          clampedDay,
          dateRange.dateFrom,
          dateRange.dateTo,
        )
      ) {
        setCalculatedDateRange(clampedDay, effectiveInterval);
      }
    },
    [
      maxDateRangeFrom,
      maxDateRangeTo,
      dateRange,
      updatePeriod,
      setCalculatedDateRange,
    ],
  );

  /**
   * Check if we can shift the view one period earlier.
   * Based on view window start (dateFrom), not selectedDay.
   */
  const canGoToPreviousPeriod = useMemo(() => {
    const periodUnit = interval === "1M" ? "month" : "isoWeek";
    const viewStart = dayjs(dateRange.dateFrom).startOf(periodUnit);
    return viewStart.isAfter(maxDateRangeFrom.startOf(periodUnit));
  }, [interval, dateRange.dateFrom, maxDateRangeFrom]);

  /**
   * Check if we can shift the view one period later.
   * Based on view window start (dateFrom), not selectedDay.
   */
  const canGoToNextPeriod = useMemo(() => {
    const periodUnit = interval === "1M" ? "month" : "isoWeek";
    const viewEnd = dayjs(dateRange.dateTo).endOf(periodUnit);
    return viewEnd.isBefore(maxDateRangeTo.endOf(periodUnit));
  }, [interval, dateRange.dateTo, maxDateRangeTo]);

  const setInterval = useCallback(
    (newInterval: AggregationPeriod) => {
      intervalRef.current = newInterval;
      setCalculatedDateRange(selectedDayRef.current, newInterval);
      updatePeriod(undefined, newInterval);
    },
    [setCalculatedDateRange, updatePeriod],
  );

  return {
    ...dateRange,
    interval,
    setInterval,
    selectedDay,
    setPeriod,
    goToPreviousPeriod,
    goToNextPeriod,
    canGoToPreviousPeriod,
    canGoToNextPeriod,
    maxDateRangeFrom,
    maxDateRangeTo,
  };
}

/**
 * Encapsulates URL query params and sessionStorage synchronization
 * for the selected period (interval + selectedDay).
 *
 * Internal to `useCashflowTimePeriodFilter` — not meant for reuse.
 */
function usePeriodState(companyId: string) {
  const DEFAULT_INTERVAL: AggregationPeriod = "1M";
  const DEFAULT_SELECTED_DAY = dayjs();

  const [persistedState, updatePersistedState] =
    useSelectedPeriodStore(companyId);

  // WARN: do not set default values in the parsers — URL state takes precedence over
  // sessionStorage and react state, so defaults here would shadow persisted values
  // and cause stale reads during the query→session→react sync cycle.
  const [queryState, setQueryState] = useQueryStates({
    interval: parseAsStringLiteral(INTERVAL_VALUES),
    selectedDay: parseAsString,
  });

  const selectedDay = useMemo(
    () => dayjs(queryState.selectedDay ?? persistedState?.selectedDay),
    [queryState.selectedDay, persistedState?.selectedDay],
  );

  const interval = useMemo(
    () => queryState.interval ?? persistedState?.interval ?? DEFAULT_INTERVAL,
    [queryState.interval, persistedState?.interval],
  );

  /**
   * Atomically updates selectedDay and/or interval in both URL query params
   * and sessionStorage. Uses a functional `setQueryState` update to read
   * the latest query state, so unchanged fields are carried forward
   * without stale closures.
   */
  const updatePeriod = useCallback(
    (newSelectedDay?: Dayjs, newInterval?: AggregationPeriod) => {
      setQueryState((prev) => {
        const resolvedDay = newSelectedDay
          ? formatDateToISO(newSelectedDay)
          : prev.selectedDay;
        const resolvedInterval = newInterval ?? prev.interval;

        updatePersistedState({
          selectedDay: resolvedDay ?? DEFAULT_SELECTED_DAY.toISOString(),
          interval: resolvedInterval ?? DEFAULT_INTERVAL,
        });

        return {
          ...prev,
          ...(newSelectedDay && { selectedDay: resolvedDay }),
          ...(newInterval && { interval: newInterval }),
        };
      });
    },
    [setQueryState, updatePersistedState],
  );

  return {
    selectedDay,
    interval,
    updatePeriod,
  };
}

